import { useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import useAuth from "../hooks/useAuth";
import { apiFetch } from "../lib/api";

const AdminDashboardPage = () => {
  const navigate = useNavigate();
    const { logout } = useAuth();

      const [users, setUsers] = useState([]);
        const [draws, setDraws] = useState([]);
          const [message, setMessage] = useState("");
            const [loading, setLoading] = useState(false);

              // 🔥 Label helper (FIX 1)
                const getLabel = (count) => {
                    if (count === 5) return "🏆 Jackpot";
                        if (count === 4) return "🥈 2nd Tier";
                            if (count === 3) return "🥉 3rd Tier";
                                return "";
                                  };

                                    const loadData = useCallback(async () => {
                                        setLoading(true);
                                            try {
                                                  const [usersResult, drawsResult] = await Promise.all([
                                                          apiFetch("/admin/users"),
                                                                  apiFetch("/admin/draw/results"),
                                                                        ]);

                                                                              if (usersResult.response.ok) {
                                                                                      setUsers(usersResult.data.users || []);
                                                                                            }

                                                                                                  if (drawsResult.response.ok) {
                                                                                                          setDraws(drawsResult.data.draws || []);
                                                                                                                }
                                                                                                                    } catch (err) {
                                                                                                                          console.error("Error loading admin data:", err);
                                                                                                                              } finally {
                                                                                                                                    setLoading(false);
                                                                                                                                        }
                                                                                                                                          }, []);

                                                                                                                                            useEffect(() => {
                                                                                                                                                loadData();
                                                                                                                                                  }, [loadData]);

                                                                                                                                                    const runDraw = async () => {
                                                                                                                                                        const { response, data } = await apiFetch("/admin/draw/run", {
                                                                                                                                                              method: "POST",
                                                                                                                                                                  });

                                                                                                                                                                      if (!response.ok) {
                                                                                                                                                                            setMessage(data.message || "Failed to run draw");
                                                                                                                                                                                  return;
                                                                                                                                                                                      }

                                                                                                                                                                                          setMessage("Draw executed successfully");
                                                                                                                                                                                              await loadData();
                                                                                                                                                                                                };

                                                                                                                                                                                                  const onLogout = async () => {
                                                                                                                                                                                                      await logout();
                                                                                                                                                                                                          navigate("/admin");
                                                                                                                                                                                                            };

                                                                                                                                                                                                              return (
                                                                                                                                                                                                                  <main className="min-h-screen bg-gray-100 px-4 py-8">
                                                                                                                                                                                                                        <div className="max-w-3xl mx-auto">
                                                                                                                                                                                                                                <div className="mb-8 text-center">
                                                                                                                                                                                                                                          <h1 className="text-4xl font-bold text-gray-900">Admin Dashboard</h1>
                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                              {/* 🔹 Controls */}
                                                                                                                                                                                                                                                                      <section className="bg-white rounded-lg shadow-md p-6 mb-6">
                                                                                                                                                                                                                                                                                <div className="flex gap-4 mb-6">
                                                                                                                                                                                                                                                                                            <button
                                                                                                                                                                                                                                                                                                          onClick={runDraw}
                                                                                                                                                                                                                                                                                                                        className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-semibold px-4 py-3 rounded-lg transition duration-200"
                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                  Run Draw
                                                                                                                                                                                                                                                                                                                                                              </button>
                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                              <button
                                                                                                                                                                                                                                                                                                                                                                                            onClick={onLogout}
                                                                                                                                                                                                                                                                                                                                                                                                          className="flex-1 bg-red-600 hover:bg-red-700 text-white font-semibold px-4 py-3 rounded-lg transition duration-200"
                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                    Logout
                                                                                                                                                                                                                                                                                                                                                                                                                                                </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {message && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="text-center text-green-600 font-semibold p-3 bg-green-50 rounded-lg mb-4">{message}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="grid grid-cols-2 gap-4 text-gray-700">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="bg-blue-50 p-4 rounded-lg">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-sm text-gray-600">Total Users</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="text-2xl font-bold text-blue-600">{users.length}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="bg-purple-50 p-4 rounded-lg">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <p className="text-sm text-gray-600">Total Draws</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p className="text-2xl font-bold text-purple-600">{draws.length}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {loading && <p className="text-center text-gray-500 mt-4 font-medium">Loading...</p>}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {/* 🔥 DRAW RESULTS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <section className="bg-white rounded-lg shadow-md p-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h2 className="text-2xl font-semibold text-gray-900 mb-6">Draw Results</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {draws.length === 0 ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <p className="text-center text-gray-500 py-8">No draws yet</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="space-y-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {draws.map((draw, i) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  key={draw._id || i}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-gray-700 mb-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="font-medium text-gray-900">Date:</span>{" "}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {new Date(draw.drawDate).toLocaleDateString()}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <p className="text-gray-700 mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="font-medium text-gray-900">Numbers:</span>{" "}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="text-indigo-600 font-semibold text-lg">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {draw.numbers?.join(", ") || "N/A"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <p className="font-medium text-gray-900 mb-2">Winners:</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {!draw.winners || draw.winners.length === 0 ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <p className="text-gray-500 ml-4">No winners</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="ml-4 space-y-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {draw.winners.map((w, idx) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div key={idx} className="bg-gray-50 p-3 rounded border-l-4 border-indigo-500">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p className="text-sm">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span className="font-medium text-gray-900">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {w.userId?.name || "Unknown"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </span>{" "}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className="text-gray-600">({w.userId?.email || "N/A"})</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-sm text-gray-700">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          Matches: <span className="font-semibold text-indigo-600">{w.matchCount}</span> {getLabel(w.matchCount)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </section>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </main>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                export default AdminDashboardPage;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                